2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Conway's Game of Life - Next Generation", () => {
6	  it("should return empty result for empty input", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell (underpopulation)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
13	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
14	  });
15	  it("should keep a 2x2 block unchanged (still life, each cell has 3 neighbors)", () => {
16	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	    const sortCells = (cells: [number, number][]) =>
18	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
19	    expect(sortCells(result)).toEqual(sortCells([[0, 0], [1, 0], [0, 1], [1, 1]]));
20	  });
